insert into public.inspection_activities
  (equipment_part_id, activity_code, activity_name, inspection_category,
   frequency_type, priority, responsible_role, standard_checklist)
select ep.equipment_part_id, d.acode, d.aname, d.cat::public.inspection_category,
       d.freq::public.frequency_type, d.prio::public.priority_level,
       d.role::public.app_user_role, d.checklist
from data d
join public.equipment e on e.equipment_code = d.ecode
join public.equipment_parts ep
  on ep.equipment_id = e.equipment_id and ep.part_code = d.pcode
on conflict (equipment_part_id, activity_code) do nothing;